import React, { useState, useEffect } from "react";
import styled from "styled-components";
import { BrowserRouter as Router, Switch, Route, Link } from "react-router-dom";
import axios from 'axios';

let productData = null;

function Product(props){
    const [product, setProduct] = useState(null)

    useEffect(() => {
        if(Object.is(productData, null)){
            axios.get(`https://api-test.innoloft.com/product/6781/`).then(res => {

                productData = res.data;
                setProduct(productData)
            }).catch(err => console.log(err))
        }
    })

    return ( 
        <div>
            <div>
                {/* image
                product main info 
                description tab - attributes tab (editable)
                tab content */}
                <div class="bg-white">
                <nav class="flex flex-col sm:flex-row">
                    <button class="text-gray-600 py-4 px-6 block hover:text-blue-500 focus:outline-none text-blue-500 border-b-2 font-medium border-blue-500">
                        Tab 1
                    </button><button class="text-gray-600 py-4 px-6 block hover:text-blue-500 focus:outline-none">
                        Tab 2
                    </button><button class="text-gray-600 py-4 px-6 block hover:text-blue-500 focus:outline-none">
                        Tab 3
                    </button><button class="text-gray-600 py-4 px-6 block hover:text-blue-500 focus:outline-none">
                        Tab 4
                    </button>
                </nav>
</div>
            </div>
                {/* user info 
                map */}
            <div>

            </div>
        </div>
    )
}

export default Product;
